,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<style>',
'    /* Responsive grid for the summary cards */',
'    .summary-grid {',
'        display: grid;',
'        grid-template-columns: repeat(1, minmax(0, 1fr));',
'        gap: 1.5rem;',
'    }',
'    ',
'    /* Responsive grid for the highlighted cards */',
'    .highlight-grid {',
'        display: grid;',
'        grid-template-columns: repeat(1, minmax(0, 1fr));',
'        gap: 1.5rem;',
'    }',
'',
'    /* Media query for larger screens (e.g., tablet and desktop) */',
'    @media (min-width: 768px) {',
'        .summary-grid {',
'            grid-template-columns: repeat(3, minmax(0, 1fr));',
'        }',
'',
'        .highlight-grid {',
'            grid-template-columns: repeat(3, minmax(0, 1fr));',
'        }',
'    }',
'</style>',
'<div style="max-width: 1152px; margin: auto; padding: 2rem;">',
'',
