wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(29707777067805882)
,p_process_sequence=>20
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'calculate monthly items'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_purchase_price NUMBER := :P2_PURCHASE_PRICE;',
'    v_down_payment   NUMBER := :P2_DOWN_PAYMENT;',
'    v_loan_period    NUMBER := :P2_LOAN_PERIOD;',
'    v_monthly_lease  NUMBER := :P2_MONTHLY_LEASE;',
'    v_depreciation   NUMBER := :P2_DEPRECIATION;',
'    v_monthly_distance NUMBER := :P2_MONTHLY_AVERAGE_DISTANCE;',
'    v_mileage        NUMBER := :P2_MILEAGE;',
'    v_fuel_price     NUMBER := :P2_FUEL;',
'    v_service_cost   NUMBER := :P2_SERVICECOST;',
'    v_services_no    NUMBER := :P2_SERVICES_NO;',
'    v_repair_cost    NUMBER := :P2_REPAIR_COST;',
'    v_insurance      NUMBER := :P2_INSURANCE;',
'    v_license_cost   NUMBER := :P2_LICENSE;',
'    v_tyre_cost      NUMBER := :P2_TYRE;',
'    v_tyre_age       NUMBER := :P2_TYRE_AGE;',
'    v_battery_cost   NUMBER := :P2_BATTERY;',
'    v_battery_age    NUMBER := :P2_BATTERYAGE;',
'    v_misc_expenses  NUMBER := :P2_MISC_EXPENSES;',
'    v_wash_cost      NUMBER := :P2_WASH;',
'    v_salary_percent NUMBER := :P2_SALARY_PERCENTAGE;',
'',
'    v_monthly_running_cost NUMBER;',
'    v_monthly_lease_payment NUMBER;',
'    v_total_monthly_expenses NUMBER;',
'    v_total_paid_5_years NUMBER;',
'    v_resale_value NUMBER;',
'    v_net_cost_ownership NUMBER;',
'    v_monthly_net_cost_ownership NUMBER;',
'',
'BEGIN',
'    IF v_purchase_price IS NOT NULL AND',
'       v_down_payment IS NOT NULL AND',
'       v_loan_period IS NOT NULL AND',
'       v_monthly_lease IS NOT NULL AND',
'       v_depreciation IS NOT NULL AND',
'       v_monthly_distance IS NOT NULL AND',
'       v_mileage IS NOT NULL AND',
'       v_fuel_price IS NOT NULL AND',
'       v_service_cost IS NOT NULL AND',
'       v_services_no IS NOT NULL AND',
'       v_repair_cost IS NOT NULL AND',
'       v_insurance IS NOT NULL AND',
'       v_license_cost IS NOT NULL AND',
'       v_tyre_cost IS NOT NULL AND',
'       v_tyre_age IS NOT NULL AND',
'       v_battery_cost IS NOT NULL AND',
'       v_battery_age IS NOT NULL AND',
'       v_misc_expenses IS NOT NULL AND',
'       v_wash_cost IS NOT NULL AND',
'       v_salary_percent IS NOT NULL',
'    THEN',
'        -- Monthly costs (formatted with commas)',
'        :P2_MONTHLY_FUEL_COST := TO_CHAR(ROUND((v_monthly_distance / v_mileage) * v_fuel_price, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYSERVICECOST := TO_CHAR(ROUND((v_service_cost * v_services_no) / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYMINORREPAIRS := TO_CHAR(ROUND(v_repair_cost / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYINSURANCE := TO_CHAR(ROUND(v_insurance / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYLICENSECOST := TO_CHAR(ROUND(v_license_cost / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYTYRECOST := TO_CHAR(ROUND(v_tyre_cost / v_tyre_age / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYBATTERYCOST := TO_CHAR(ROUND(v_battery_cost / v_battery_age / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLY_MISC_COST := TO_CHAR(ROUND(v_misc_expenses / 12, 2), ''FM999,999,990.00'');',
'        :P2_MONTHLYWASH := TO_CHAR(ROUND(v_wash_cost / 12, 2), ''FM999,999,990.00'');',
'',
'        -- Summary costs',
'        v_monthly_running_cost :=',
'            (v_monthly_distance / v_mileage) * v_fuel_price +',
'            (v_service_cost * v_services_no) / 12 +',
'            v_repair_cost / 12 +',
'            v_insurance / 12 +',
'            v_license_cost / 12 +',
'            v_tyre_cost / v_tyre_age / 12 +',
'            v_battery_cost / v_battery_age / 12 +',
'            v_misc_expenses / 12 +',
'            v_wash_cost / 12;',
'        :P2_TOTAL_MONTHLY_RUNNING_COST := TO_CHAR(ROUND(v_monthly_running_cost, 2), ''FM999,999,990.00'');',
'',
'        v_monthly_lease_payment := (v_purchase_price - (v_purchase_price * v_down_payment / 100)) / 100000 * v_monthly_lease;',
'        :P2_MONTHLY_LEASE_PAYMENT := TO_CHAR(ROUND(v_monthly_lease_payment, 2), ''FM999,999,990.00'');',
'',
'        v_total_monthly_expenses := v_monthly_running_cost + v_monthly_lease_payment;',
'        :P2_TOTAL_MONTHLY_DIRECT_EXPENSES := TO_CHAR(ROUND(v_total_monthly_expenses, 2), ''FM999,999,990.00'');',
'',
'        v_total_paid_5_years := (v_total_monthly_expenses * v_loan_period) + (v_purchase_price * v_down_payment / 100);',
'        :P2_TOTAL_PAID_OVER_5_YEARS := TO_CHAR(ROUND(v_total_paid_5_years, 2), ''FM999,999,990.00'');',
'',
'        v_resale_value := v_purchase_price - (v_purchase_price * v_depreciation / 100);',
'        :P2_ESTIMATED_RESALE_VALUE := TO_CHAR(ROUND(v_resale_value, 2), ''FM999,999,990.00'');',
'',
'        v_net_cost_ownership := v_total_paid_5_years - v_resale_value;',
'        :P2_NET_COST_OF_OWNERSHIP := TO_CHAR(ROUND(v_net_cost_ownership, 2), ''FM999,999,990.00'');',
'',
'        v_monthly_net_cost_ownership := v_net_cost_ownership / v_loan_period;',
'        :P2_MONTHLY_NET_COST_OF_OWNERSHIP_5_YEAR := TO_CHAR(ROUND(v_monthly_net_cost_ownership, 2), ''FM999,999,990.00'');',
'',
'        :P2_REQUIRED_MONTHLY_INCOME_EXPENDITURE_BASIS := TO_CHAR(ROUND(v_total_monthly_expenses / (v_salary_percent / 100), 2), ''FM999,999,990.00'');',
'        :P2_REQUIRED_MONTHLY_INCOME_EQUITY_BASIS_1 := TO_CHAR(ROUND(v_monthly_net_cost_ownership / (v_salary_percent / 100), 2), ''FM999,999,990.00'');',
'    END IF;',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>29707777067805882
);
end;
